-- Composite: leftmost-prefix rule
CREATE INDEX idx_orders_uid_status ON orders(user_id, status);
-- Serves: WHERE user_id=? or WHERE user_id=? AND status=?
-- Not:    WHERE status=?  (skips leftmost)

-- Partial index: hot subset only
CREATE INDEX idx_active ON orders(user_id) WHERE status='OPEN';

-- Covering (Postgres): include columns without indexing them
CREATE INDEX idx_cover ON orders(user_id) INCLUDE (total, status);
